// Prepare data for LLM
const scanStats = items[0].json;
const vulnerabilities = items.slice(1).filter(i => i.json.vulnerability_id);
const patches = items.slice(1).filter(i => i.json.patch_id);

const reportData = {
  period: "Last 7 Days",
  generated_at: new Date().toISOString(),
  statistics: {
    total_scans: scanStats.total_scans || 0,
    total_vulnerabilities: scanStats.total_vulnerabilities || 0,
    by_severity: {
      critical: scanStats.critical_count || 0,
      high: scanStats.high_count || 0,
      medium: scanStats.medium_count || 0,
      low: scanStats.low_count || 0
    }
  },
  top_vulnerabilities: vulnerabilities.slice(0, 10).map(v => ({
    cve: v.json.cve,
    title: v.json.title,
    cvss: v.json.cvss_score,
    severity: v.json.severity
  })),
  patches_applied: patches.length,
  patch_details: patches.slice(0, 5).map(p => ({
    title: p.json.title,
    vulnerabilities_fixed: p.json.vulnerabilities_fixed?.length || 0
  }))
};

return [{ json: reportData }];

// Parse AI-generated report
const ollamaResponse = items[0].json.response;
const reportData = items[0].json;

let aiSummary;
try {
  const jsonMatch = ollamaResponse.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    aiSummary = JSON.parse(jsonMatch[0]);
  } else {
    aiSummary = {
      executive_summary: ollamaResponse.substring(0, 300),
      security_posture: 75,
      key_findings: ["Review AI response for details"],
      critical_items: [],
      remediation_progress: "In progress",
      compliance_scores: {
        cis: 80,
        nist: 75,
        pci_dss: 70
      },
      recommendations: ["Continue monitoring", "Apply pending patches"]
    };
  }
} catch (error) {
  aiSummary = {
    error: error.message,
    raw_response: ollamaResponse.substring(0, 500)
  };
}

const finalReport = {
  report_id: `report_${Date.now()}`,
  title: `Weekly Security Compliance Report - ${new Date().toLocaleDateString()}`,
  period: reportData.period,
  generated_at: reportData.generated_at,
  statistics: reportData.statistics,
  ai_analysis: aiSummary,
  top_vulnerabilities: reportData.top_vulnerabilities,
  patches_applied: reportData.patches_applied,
  patch_details: reportData.patch_details,
  report_type: "weekly_compliance"
};

return [{ json: finalReport }];

// Simulate email sending
const report = items[0].json;

const emailData = {
  to: ["security-team@example.com", "management@example.com"],
  subject: `Weekly Security Report - ${new Date().toLocaleDateString()}`,
  body: `
Weekly Security Compliance Report
================================

Period: ${report.period}
Generated: ${new Date(report.generated_at).toLocaleString()}

EXECUTIVE SUMMARY
${report.ai_analysis.executive_summary}

SECURITY POSTURE: ${report.ai_analysis.security_posture}/100

STATISTICS
- Total Scans: ${report.statistics.total_scans}
- Total Vulnerabilities: ${report.statistics.total_vulnerabilities}
- Critical: ${report.statistics.by_severity.critical}
- High: ${report.statistics.by_severity.high}
- Medium: ${report.statistics.by_severity.medium}
- Low: ${report.statistics.by_severity.low}

PATCHES APPLIED: ${report.patches_applied}

COMPLIANCE SCORES
- CIS Benchmark: ${report.ai_analysis.compliance_scores.cis}%
- NIST: ${report.ai_analysis.compliance_scores.nist}%
- PCI-DSS: ${report.ai_analysis.compliance_scores.pci_dss}%

RECOMMENDATIONS
${report.ai_analysis.recommendations.map((r, i) => `${i + 1}. ${r}`).join('\n')}

Full report available in the dashboard.
  `,
  sent_at: new Date().toISOString(),
  status: "sent"
};

return [
  {
    json: {
      ...report,
      email: emailData
    }
  }
];
